BEGIN; CREATE OR REPLACE FUNCTION public.undo_outbound_delivery(p_plan_id uuid) RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path = public, pg_temp AS $$ BEGIN IF auth.uid() IS NULL THEN RAISE EXCEPTION 'Ban can dang nhap de thao tac.' USING ERRCODE = '42501'; END IF; RAISE EXCEPTION 'Huy tung ma tai Ke hoach giao hang da tat. Hay dieu chinh hang hoac huy phieu tao nham tai Nhat ky giao hang.' USING ERRCODE = '0A000'; END; $$; REVOKE ALL ON FUNCTION public.undo_outbound_delivery(uuid) FROM PUBLIC, anon, authenticated; GRANT EXECUTE ON FUNCTION public.undo_outbound_delivery(uuid) TO authenticated; NOTIFY pgrst,'reload schema'; COMMIT;
